                                    if (val === "add_new") {
                                        setShowAddCourse(true);
                                    } else {
                                        setForm((f) => ({ ...f, course: val }));
                                        setShowAddCourse(false);
                                    }
                                }}
                                required
                                style={{ ...inputStyle, height: 44, padding: "0 14px", WebkitAppearance: "none" } as React.CSSProperties}
                                onFocus={onFocus} onBlur={onBlur}
