            const newIps = [...m.ips];
            newIps[index] = { ...newIps[index], [key]: value };
            return { ...m, ips: newIps };
        });
    };
    const removeIp = (index: number) => {
        setMeta(m => ({ ...m, ips: m.ips.filter((_, i) => i !== index) }));
    };

    return (
